SELECT 
FROM EVS_SCORE es
WHERE es.ACTIVITY != 2

    AND es.RESUME_SEQ = #{resumeSeq, jdbcType=VARCHAR}


    AND es.SCORE_TYPE = #{scoreTypeSearch, jdbcType=VARCHAR}


    AND es.ACTIVITY = #{activitySearch, jdbcType=VARCHAR}

ORDER BY TO_NUMBER(es.SEQ)

SELECT 
FROM EVS_SCORE es
WHERE es.SEQ     = #{seq,    jdbcType=VARCHAR}
